namespace sv_4b3a19f860a54c43bc0761bc27e3429e.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public class ShipmentDetails
{
    public required string TrackingNumber { get; set; }
    public required string Status { get; set; }
    public required string Location { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public List<StatusUpdate> StatusUpdates { get; set; } = [];
}

public class StatusUpdate
{
    public required string Description { get; set; }
    public required string Location { get; set; }
    public DateTime Timestamp { get; set; }
}

using System.Net.Http.Json;

namespace sv_4b3a19f860a54c43bc0761bc27e3429e.Client.Services;

public class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct)
            ?? throw new InvalidOperationException("Failed to deserialize shipment response.");
    }
}

using sv_4b3a19f860a54c43bc0761bc27e3429e.Client.Services;

namespace sv_4b3a19f860a54c43bc0761bc27e3429e.Services;

public class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = DateTime.UtcNow.AddDays(2),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "New York, NY", Timestamp = DateTime.UtcNow.AddDays(-3) },
                new StatusUpdate { Description = "Departed facility", Location = "New York, NY", Timestamp = DateTime.UtcNow.AddDays(-2) },
                new StatusUpdate { Description = "Arrived at sorting center", Location = "Chicago, IL", Timestamp = DateTime.UtcNow.AddDays(-1) },
            ]
        },
        ["PKG-002"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = null,
            StatusUpdates =
            [
                new StatusUpdate { Description = "Package picked up", Location = "Seattle, WA", Timestamp = DateTime.UtcNow.AddDays(-5) },
                new StatusUpdate { Description = "In transit", Location = "Portland, OR", Timestamp = DateTime.UtcNow.AddDays(-4) },
                new StatusUpdate { Description = "Out for delivery", Location = "San Francisco, CA", Timestamp = DateTime.UtcNow.AddDays(-2) },
                new StatusUpdate { Description = "Delivered", Location = "San Francisco, CA", Timestamp = DateTime.UtcNow.AddDays(-2).AddHours(4) },
            ]
        },
        ["PKG-003"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-003",
            Status = "Processing",
            Location = "Dallas, TX",
            EstimatedDelivery = DateTime.UtcNow.AddDays(5),
            StatusUpdates =
            [
                new StatusUpdate { Description = "Label created", Location = "Dallas, TX", Timestamp = DateTime.UtcNow.AddHours(-6) },
            ]
        },
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        if (SeedData.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"Shipment with tracking number '{trackingNumber}' was not found.");
    }
}

