+@using sv_4b3a19f860a54c43bc0761bc27e3429e.Client.Services
+@inject IShipmentService ShipmentService
+@inject ILogger<ShipmentTracker> Logger
+@implements IDisposable
+
+<PageTitle>Shipment @TrackingNumber</PageTitle>
+
+<h1>Shipment Tracking</h1>
+
+@if (_loading)
+{
+    <div class="loading-placeholder">
+        <p><em>Loading shipment details for @TrackingNumber&hellip;</em></p>
+    </div>
+}
+else if (_errorMessage is not null)
+{
+    <div class="alert alert-danger">
+        <p>@_errorMessage</p>
+        <button class="btn btn-primary" @onclick="RetryAsync">Retry</button>
+    </div>
+}
+else if (_shipment is not null)
+{
+    <div class="shipment-details">
+        <dl>
+            <dt>Tracking Number</dt>
+            <dd>@_shipment.TrackingNumber</dd>
+
+            <dt>Status</dt>
+            <dd>@_shipment.Status</dd>
+
+            <dt>Current Location</dt>
+            <dd>@_shipment.Location</dd>
+
+            @if (_shipment.EstimatedDelivery.HasValue)
+            {
+                <dt>Estimated Delivery</dt>
+                <dd>@_shipment.EstimatedDelivery.Value.ToString("f")</dd>
+            }
+        </dl>
+
+        @if (_shipment.StatusUpdates.Count > 0)
+        {
+            <h2>Tracking History</h2>
+            <table class="table">
+                <thead>
+                    <tr>
+                        <th>Date</th>
+                        <th>Location</th>
+                        <th>Description</th>
+                    </tr>
+                </thead>
+                <tbody>
+                    @foreach (var update in _shipment.StatusUpdates.OrderByDescending(u => u.Timestamp))
+                    {
+                        <tr>
+                            <td>@update.Timestamp.ToString("g")</td>
+                            <td>@update.Location</td>
+                            <td>@update.Description</td>
+                        </tr>
+                    }
+                </tbody>
+            </table>
+        }
+    </div>
+}
+
+@code {
+    [Parameter]
+    public string TrackingNumber { get; set; } = default!;
+
+    private ShipmentDetails? _shipment;
+    private bool _loading;
+    private string? _errorMessage;
+    private CancellationTokenSource? _cts;
+
+    protected override Task OnParametersSetAsync()
+    {
+        return LoadShipmentAsync();
+    }
+
+    private async Task LoadShipmentAsync()
+    {
+        // Cancel any in-flight request
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = new CancellationTokenSource();
+        var ct = _cts.Token;
+
+        _loading = true;
+        _errorMessage = null;
+        _shipment = null;
+
+        try
+        {
+            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
+        }
+        catch (OperationCanceledException) when (ct.IsCancellationRequested)
+        {
+            // Navigation changed or component disposed — do nothing
+            return;
+        }
+        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
+        {
+            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
+            _errorMessage = "The request timed out. Please try again.";
+        }
+        catch (TimeoutException ex)
+        {
+            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
+            _errorMessage = "The request timed out. Please try again.";
+        }
+        catch (Exception ex)
+        {
+            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
+            _errorMessage = "Something went wrong loading shipment details. Please try again.";
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private Task RetryAsync() => LoadShipmentAsync();
+
+    public void Dispose()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+    }
+}
+

